Javascript.validate:
var val = Services.getValue(Balancedue.dataBinding);
var err = null;
var maxVal = 999999.99;

if('0.00' != val)
{
	err = validateCurrencyValue(val, maxVal);
	if( null == err )
	{ 	
		var fVal = WPU.formatToTwoDP(val);
		Services.setValue(Balancedue.dataBinding, fVal);
	}
}
return err;

