function DefaultCurrency9087() {}
DefaultCurrency9087.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency9087.tabIndex = -1;
DefaultCurrency9087.maxLength = 1;
DefaultCurrency9087.isReadOnly = function(){return true;}
DefaultCurrency9087.isTemporary = function(){return true;}
DefaultCurrency9087.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency9087.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
